 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Administration { static function abcd(array $fallback = []): object { $framework = Resources::getPathOptimised(dirname(__DIR__, 2)); if ($root = Resources::readJSON( "$framework/composer.json", ['tapmeppe' => ['root' => '']] )['tapmeppe']['root']) $framework0 = "$framework/$root"; else $framework0 = $framework; $assets = "$framework0/assets"; $path = "$framework0/configuration.json"; $resources = "$framework0/resources"; $configuration = (object) Resources::readJSON($path, [ 'database' => [ 'database' => '', 'host' => 'localhost', 'password' => '', 'port' => 3306, 'username' => '', ], 'mode' => [ 'color' => true, 'development' => false, ], ...$fallback, ]); define('TAPMEPPE_ASSETS', $assets); define('TAPMEPPE_DOMAIN', 'tapmeppe.work'); define('TAPMEPPE_EMAIL', 'administrator@' . TAPMEPPE_DOMAIN); define('TAPMEPPE_FRAMEWORK', $framework); define('TAPMEPPE_LOGS', Resources::createDirectory("$resources/logs")); define('TAPMEPPE_NAMESPACE', preg_replace('/[a-z]+$/', '', __NAMESPACE__)); define('TAPMEPPE_MODE_COLOR', $configuration->mode['color']); define('TAPMEPPE_MODE_DEVELOPMENT', $configuration->mode['development']); define('TAPMEPPE_RESOURCES', $resources); define('TAPMEPPE_SOURCE', "$framework/src"); define('TAPMEPPE_UMBRELLA', 'tapmeppe'); define('TAPMEPPE_VERSION', '0.0.0'); return (object) [ 'configuration' => $configuration, 'paths' => (object) ( compact('assets', 'framework', 'resources', 'root') + [ 'configuration' => $path, 'logs' => TAPMEPPE_LOGS, ] ), ]; } } 